from collections import deque

def shortest_path(graph, start, goal):
    queue = deque([(start, [start])])
    visited = set()
    while queue:
        node, path = queue.popleft()
        if node == goal:
            return path
        if node in visited:
            continue
        visited.add(node)
        for neighbour in graph.get(node, []):
            queue.append((neighbour, path + [neighbour]))
    return []
```

