def topological_sort(dependencies):
    from heapq import heappush, heappop

    nodes = set(dependencies.keys())
    for prereqs in dependencies.values():
        nodes.update(prereqs)

    in_degree = {node: 0 for node in nodes}
    dependents = {node: [] for node in nodes}

    for node, prereqs in dependencies.items():
        in_degree[node] = len(prereqs)
        for p in prereqs:
            dependents[p].append(node)

    heap = []
    for node in nodes:
        if in_degree[node] == 0:
            heappush(heap, node)

    result = []
    while heap:
        node = heappop(heap)
        result.append(node)
        for dependent in dependents[node]:
            in_degree[dependent] -= 1
            if in_degree[dependent] == 0:
                heappush(heap, dependent)

    if len(result) != len(nodes):
        raise ValueError("Cycle exists in dependencies")

    return result
